type browseColumnOption struct {
	Key   string
	Label string
}

func browseColumnOptions() []browseColumnOption {
	return []browseColumnOption{
		{Key: "display_id", Label: "Display ID"},
		{Key: "name", Label: "Name"},
		{Key: "entry_type", Label: "Entry Type"},
		{Key: "rank_out", Label: "Rank Out"},
		{Key: "unit", Label: "Unit"},
		{Key: "pension_state", Label: "Pension State"},
		{Key: "review_status", Label: "Review Status"},
		{Key: "last_edited", Label: "Last Edited"},
	}
}

func browsePageCount(state viewmodel.BrowseState) int {
	if state.PageSize < 1 || state.Total < 1 {
		return 1
	}
	count := state.Total / state.PageSize
	if state.Total%state.PageSize != 0 {
		count++
	}
	if count < 1 {
		return 1
	}
	return count
}

func browsePageHref(state viewmodel.BrowseState, page int) string {
	values := url.Values{}
	values.Set("page", fmt.Sprintf("%d", page))
	values.Set("page_size", fmt.Sprintf("%d", state.PageSize))
	if strings.TrimSpace(state.Scope) != "" {
		values.Set("scope", state.Scope)
	}
	if strings.TrimSpace(state.Sort) != "" {
		values.Set("sort", state.Sort)
	}
	if strings.TrimSpace(state.EntryType) != "" {
		values.Set("entry_type", state.EntryType)
	}
	if strings.TrimSpace(state.Unit) != "" {
		values.Set("unit", state.Unit)
	}
	if strings.TrimSpace(state.PensionState) != "" {
		values.Set("pension_state", state.PensionState)
	}
	if strings.TrimSpace(state.ReviewStatus) != "" {
		values.Set("review_status", state.ReviewStatus)
	}
	if strings.TrimSpace(state.ConfederateHomeStatus) != "" {
		values.Set("confederate_home_status", state.ConfederateHomeStatus)
	}
	return "/browse/results?" + values.Encode()
}

func browseSummary(state viewmodel.BrowseState) string {
	scope := "All records"
	switch state.Scope {
	case "recently_added":
		scope = "Recently added"
	case "last_import":
		scope = "Last import"
	}
	return fmt.Sprintf("%s | %s", scope, browseSortLabel(state.Sort))
}

func browseActiveFilters(state viewmodel.BrowseState) []string {
	filters := make([]string, 0, 5)
	if entryType := strings.TrimSpace(state.EntryType); entryType != "" {
		filters = append(filters, "Entry Type: "+browseEntryTypeLabel(entryType))
	}
	if pensionState := strings.TrimSpace(state.PensionState); pensionState != "" {
		filters = append(filters, "Pension State: "+pensionState)
	}
	if unit := strings.TrimSpace(state.Unit); unit != "" {
		filters = append(filters, "Unit: "+unit)
	}
	if reviewStatus := strings.TrimSpace(state.ReviewStatus); reviewStatus != "" {
		filters = append(filters, "Review Status: "+browseReviewStatusLabel(reviewStatus))
	}
	if confederateHomeStatus := strings.TrimSpace(state.ConfederateHomeStatus); confederateHomeStatus != "" {
		filters = append(filters, "Confederate Home Status: "+confederateHomeStatus)
	}
	return filters
}

func browseEntryTypeLabel(entryType string) string {
	switch strings.TrimSpace(strings.ToLower(entryType)) {
	case "soldier":
		return "Soldier"
	case "linked_person":
		return "Person Record"
	case "wife":
		return "Wife"
	case "widow":
		return "Widow"
	default:
		return entryType
	}
}

func browseReviewStatusLabel(reviewStatus string) string {
	switch strings.TrimSpace(strings.ToLower(reviewStatus)) {
	case "clean":
		return "Clean Only"
	case "review":
		return "Needs Review"
	default:
		return reviewStatus
	}
}

func browseSortLabel(sort string) string {
	switch strings.TrimSpace(sort) {
	case "display_id_desc":
		return "Display ID descending"
	case "name_asc":
		return "Name"
	case "last_edited_desc":
		return "Last edited"
	case "created_desc":
		return "Created"
	default:
		return "Display ID ascending"
	}
}

func browseCellValue(value string) string {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return "—"
	}
	return trimmed
}

func browseReviewStatus(record viewmodel.PersonRecord) string {
	if record.NeedsReview {
		return "Needs Review"
	}
	return "Clean"
}

func browseTimestamp(values ...string) string {
	for _, value := range values {
		if formatted := formatAuditTimestamp(value); formatted != "" {
			return formatted
		}
	}
	return "—"
}

